    val s = num.toString
    if (s != s.reverse) return false
    val counts = s.groupBy(identity).mapValues(_.length)
    counts.forall { case (c, cnt) =>
      val digit = c.asDigit
      digit >= 1 && digit <= 9 && digit == cnt
    }
  }

  var candidate = n + 1
  while (true) {
    if (isSpecialNumber(candidate)) {
      return candidate
    }
    candidate += 1
  }
}
